"use client";

import { useState, useEffect } from "react";

type Quadrant = "MIND" | "BODY" | "SPIRIT" | "VOCATION";
type Stage =
  | "Discovery"
  | "Dissonance"
  | "Uncertain"
  | "Integrating"
  | "Mastery";

interface QuadrantData {
  quadrant: Quadrant;
  score: number;
  stage: Stage;
  label: string;
  borderColor: string;
  emoji: string;
}

const SCORE_COLORS: Record<string, string> = {
  "1": "#FF3B3B",
  "2": "#FFB800",
  "3": "#00FF88",
};

const STAGE_LABELS: Record<Stage, string> = {
  Discovery: "Keşif",
  Dissonance: "Uyumsuzluk",
  Uncertain: "Belirsiz",
  Integrating: "Entegrasyon",
  Mastery: "Ustalık",
};

const QUADRANT_LABELS: Record<Quadrant, string> = {
  MIND: "ZİHİN",
  BODY: "BEDEN",
  SPIRIT: "RUH",
  VOCATION: "İŞ/KARİYER",
};

const getScoreColor = (score: number): string => {
  const key = Math.floor(score).toString();
  return SCORE_COLORS[key] || "#666666";
};

const DEFAULT_QUADRANTS: QuadrantData[] = [
  {
    quadrant: "MIND",
    score: 2.1,
    stage: "Dissonance",
    label: "MIND",
    borderColor: "#3B82F6",
    emoji: "🧠",
  },
  {
    quadrant: "BODY",
    score: 2.3,
    stage: "Discovery",
    label: "BODY",
    borderColor: "#22C55E",
    emoji: "💪",
  },
  {
    quadrant: "SPIRIT",
    score: 1.3,
    stage: "Discovery",
    label: "SPIRIT",
    borderColor: "#A855F7",
    emoji: "🔮",
  },
  {
    quadrant: "VOCATION",
    score: 2.2,
    stage: "Uncertain",
    label: "VOCATION",
    borderColor: "#F97316",
    emoji: "⚡",
  },
];

const STAGES: Stage[] = [
  "Discovery",
  "Dissonance",
  "Uncertain",
  "Integrating",
  "Mastery",
];

interface QuadrantDashboardProps {
  activeQuadrantFilter: Quadrant | null;
  onQuadrantClick: (q: Quadrant | null) => void;
}

export default function QuadrantDashboard({
  activeQuadrantFilter,
  onQuadrantClick,
}: QuadrantDashboardProps) {
  const [quadrants, setQuadrants] = useState<QuadrantData[]>(DEFAULT_QUADRANTS);
  const [editingId, setEditingId] = useState<Quadrant | null>(null);
  const [editScore, setEditScore] = useState("");
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem("goat-quadrants-v1");
    if (saved) {
      try {
        setQuadrants(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse quadrant data");
      }
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem("goat-quadrants-v1", JSON.stringify(quadrants));
    }
  }, [quadrants, isLoaded]);

  const handleScoreUpdate = (q: Quadrant) => {
    const val = parseFloat(editScore);
    if (isNaN(val) || val < 0 || val > 3.9) return;
    setQuadrants((prev) =>
      prev.map((qd) =>
        qd.quadrant === q ? { ...qd, score: Math.round(val * 10) / 10 } : qd,
      ),
    );
    setEditingId(null);
    setEditScore("");
  };

  const cycleStage = (q: Quadrant) => {
    setQuadrants((prev) =>
      prev.map((qd) => {
        if (qd.quadrant !== q) return qd;
        const idx = STAGES.indexOf(qd.stage);
        const nextIdx = (idx + 1) % STAGES.length;
        return { ...qd, stage: STAGES[nextIdx] };
      }),
    );
  };

  // Calculate overall HUMAN 3.0 score
  const overallScore =
    quadrants.reduce((sum, q) => sum + q.score, 0) / quadrants.length;

  if (!isLoaded) return null;

  return (
    <section className="mb-6">
      <div className="flex items-center justify-between mb-3">
        <h2 className="text-xs uppercase tracking-[0.25em] text-text-muted">
          HUMAN 3.0 — Quadrant Dashboard
        </h2>
        <div className="flex items-center gap-2">
          <span className="text-[9px] uppercase tracking-widest text-text-muted">
            Genel Skor
          </span>
          <span
            className="text-sm font-bold"
            style={{ color: getScoreColor(overallScore) }}
          >
            {overallScore.toFixed(1)}
          </span>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
        {quadrants.map((qd) => {
          const isActive = activeQuadrantFilter === qd.quadrant;
          const scoreColor = getScoreColor(qd.score);

          return (
            <div
              key={qd.quadrant}
              onClick={() => onQuadrantClick(isActive ? null : qd.quadrant)}
              role="button"
              tabIndex={0}
              className={`
                                brutalist-card p-3 text-left transition-all duration-300 cursor-pointer
                                ${
                                  isActive
                                    ? "bg-surface-hover shadow-[0_0_15px_rgba(255,255,255,0.05)]"
                                    : "bg-surface/20 hover:bg-surface-hover"
                                }
                            `}
              style={{
                borderColor: isActive ? qd.borderColor : "var(--color-border)",
                borderWidth: isActive ? "2px" : "1px",
              }}
            >
              <div className="flex items-center justify-between mb-2">
                <span
                  className="text-[10px] font-bold uppercase tracking-[0.2em]"
                  style={{ color: qd.borderColor }}
                >
                  {qd.emoji} {QUADRANT_LABELS[qd.quadrant]}
                </span>
                {isActive && (
                  <span className="text-[8px] uppercase tracking-widest text-text-muted bg-surface px-1.5 py-0.5 border border-border">
                    FİLTRE AKTİF
                  </span>
                )}
              </div>

              {/* Score */}
              {editingId === qd.quadrant ? (
                <div
                  className="flex gap-1"
                  onClick={(e) => e.stopPropagation()}
                >
                  <input
                    type="number"
                    step="0.1"
                    min="0"
                    max="3.9"
                    value={editScore}
                    onChange={(e) => setEditScore(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") handleScoreUpdate(qd.quadrant);
                      if (e.key === "Escape") setEditingId(null);
                    }}
                    className="bg-background border border-border text-sm text-text px-1.5 py-0.5 w-14 focus:outline-none focus:border-text-muted font-bold"
                    autoFocus
                  />
                  <button
                    onClick={() => handleScoreUpdate(qd.quadrant)}
                    className="text-[9px] uppercase font-bold text-accent-green px-1"
                  >
                    ✓
                  </button>
                </div>
              ) : (
                <div
                  className="text-2xl font-bold mb-1 cursor-pointer hover:opacity-70 transition-opacity"
                  style={{ color: scoreColor }}
                  onClick={(e) => {
                    e.stopPropagation();
                    setEditingId(qd.quadrant);
                    setEditScore(qd.score.toString());
                  }}
                  title="Skoru düzenlemek için tıkla"
                >
                  {qd.score.toFixed(1)}
                </div>
              )}

              {/* Stage */}
              <span
                className="text-[9px] uppercase tracking-widest text-text-muted hover:text-text transition-colors cursor-pointer"
                onClick={(e) => {
                  e.stopPropagation();
                  cycleStage(qd.quadrant);
                }}
                title="Aşamayı değiştirmek için tıkla"
              >
                {STAGE_LABELS[qd.stage]}
              </span>
            </div>
          );
        })}
      </div>

      {/* Score Legend */}
      <div className="flex gap-4 mt-2 justify-end">
        <span className="text-[8px] uppercase tracking-widest flex items-center gap-1">
          <span
            className="w-2 h-2 inline-block"
            style={{ backgroundColor: "#FF3B3B" }}
          />
          <span className="text-text-muted">1.x Kritik</span>
        </span>
        <span className="text-[8px] uppercase tracking-widest flex items-center gap-1">
          <span
            className="w-2 h-2 inline-block"
            style={{ backgroundColor: "#FFB800" }}
          />
          <span className="text-text-muted">2.x Gelişiyor</span>
        </span>
        <span className="text-[8px] uppercase tracking-widest flex items-center gap-1">
          <span
            className="w-2 h-2 inline-block"
            style={{ backgroundColor: "#00FF88" }}
          />
          <span className="text-text-muted">3.x Güçlü</span>
        </span>
      </div>
    </section>
  );
}

export type { Quadrant };

"use client";

import { useState } from "react";

interface ShadowJournalModalProps {
    open: boolean;
    onClose: () => void;
}

export default function ShadowJournalModal({ open, onClose }: ShadowJournalModalProps) {
    const [q1, setQ1] = useState("");
    const [q2, setQ2] = useState("");
    const [q3, setQ3] = useState("");
    const [submitted, setSubmitted] = useState(false);

    if (!open) return null;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (q1.trim().length < 5 || q2.trim().length < 5 || q3.trim().length < 5) return;
        setSubmitted(true);
        setTimeout(() => {
            onClose();
            setSubmitted(false);
            setQ1("");
            setQ2("");
            setQ3("");
        }, 2000);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm">
            <div className="brutalist-card border-text p-6 md:p-8 bg-black w-full max-w-2xl relative overflow-y-auto max-h-[90vh]">
                {!submitted ? (
                    <>
                        <div className="flex justify-between items-start mb-6">
                            <div>
                                <h2 className="text-xl md:text-2xl font-black uppercase tracking-[0.3em] text-text">
                                    GÖLGE GÜNLÜĞÜ
                                </h2>
                                <p className="text-xs text-text-muted mt-2 tracking-widest uppercase">
                                    GECE YÜZLEŞMESİ. ONAY ARAMA İHTİYACINLA YÜZLEŞ.
                                </p>
                            </div>
                            <button
                                onClick={onClose}
                                className="text-text-muted hover:text-text text-xl leading-none"
                            >
                                ×
                            </button>
                        </div>

                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div>
                                <label className="text-xs uppercase tracking-widest text-text font-bold block mb-2">
                                    1. Bugün nerede "Uysallık" (Nice Guy refleksi) gösterdin?
                                </label>
                                <textarea
                                    value={q1}
                                    onChange={(e) => setQ1(e.target.value)}
                                    placeholder="Kimden onay bekledin? Kime hayır diyemedin?"
                                    className="w-full bg-surface/30 border border-border p-3 text-sm text-text focus:outline-none focus:border-text transition-colors min-h-[80px] resize-none"
                                />
                            </div>

                            <div>
                                <label className="text-xs uppercase tracking-widest text-text font-bold block mb-2">
                                    2. Sınırlarını koruyabildin mi?
                                </label>
                                <textarea
                                    value={q2}
                                    onChange={(e) => setQ2(e.target.value)}
                                    placeholder="Nerede taviz verdin veya nerede sağlam durdun?"
                                    className="w-full bg-surface/30 border border-border p-3 text-sm text-text focus:outline-none focus:border-text transition-colors min-h-[80px] resize-none"
                                />
                            </div>

                            <div>
                                <label className="text-xs uppercase tracking-widest text-text font-bold block mb-2">
                                    3. Kendi isteklerini başkalarınınkinin önüne koyabildin mi?
                                </label>
                                <textarea
                                    value={q3}
                                    onChange={(e) => setQ3(e.target.value)}
                                    placeholder="Yoksa yine başkalarını mutlu etmek için kendi zamanından mı çaldın?"
                                    className="w-full bg-surface/30 border border-border p-3 text-sm text-text focus:outline-none focus:border-text transition-colors min-h-[80px] resize-none"
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={q1.length < 5 || q2.length < 5 || q3.length < 5}
                                className={`w-full py-4 text-sm uppercase tracking-[0.3em] font-black transition-all mt-4 ${q1.length >= 5 && q2.length >= 5 && q3.length >= 5
                                    ? "bg-text text-black hover:bg-text-muted"
                                    : "bg-surface text-text-muted cursor-not-allowed border border-border"
                                    }`}
                            >
                                Yüzleşmeyi Tamamla
                            </button>
                        </form>
                    </>
                ) : (
                    <div className="py-12 text-center space-y-4">
                        <span className="text-6xl text-text block mb-4">👁️</span>
                        <h3 className="text-xl uppercase tracking-[0.4em] font-black text-text">
                            GÖLGE KAYDEDİLDİ
                        </h3>
                        <p className="text-sm text-text-muted max-w-md mx-auto uppercase tracking-widest">
                            Farkındalık değişimin ilk adımıdır. Yarın aynı zayıflıkları tekrarlama.
                        </p>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";

export default function StreakCounter() {
    const [streak, setStreak] = useState(0);
    const [bestStreak, setBestStreak] = useState(0);
    const [isLoaded, setIsLoaded] = useState(false);

    useEffect(() => {
        const savedStreak = localStorage.getItem("goat-streak-v1");
        const savedBest = localStorage.getItem("goat-streak-best-v1");

        if (savedStreak) setStreak(parseInt(savedStreak, 10));
        if (savedBest) setBestStreak(parseInt(savedBest, 10));

        // Check yesterday's completion status
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayKey = yesterday.toISOString().split("T")[0];
        const yesterdayComplete = localStorage.getItem(`goat-day-complete-${yesterdayKey}`);

        // If yesterday wasn't completed in EndDay, check if streak should be broken
        const lastStreakDate = localStorage.getItem("goat-streak-last-date");
        if (lastStreakDate) {
            const lastDate = new Date(lastStreakDate);
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            lastDate.setHours(0, 0, 0, 0);

            const diffDays = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 60 * 60 * 24));

            // If more than 1 day gap, streak is broken
            if (diffDays > 1 && !yesterdayComplete) {
                setStreak(0);
                localStorage.setItem("goat-streak-v1", "0");
            }
        }

        setIsLoaded(true);

        // Listen for streak update events (from EndDayButton)
        const handleStreakUpdate = () => {
            const newStreak = parseInt(localStorage.getItem("goat-streak-v1") || "0", 10);
            const newBest = parseInt(localStorage.getItem("goat-streak-best-v1") || "0", 10);
            setStreak(newStreak);
            setBestStreak(newBest);
        };

        window.addEventListener("streakUpdated", handleStreakUpdate);
        return () => window.removeEventListener("streakUpdated", handleStreakUpdate);
    }, []);

    if (!isLoaded) return null;

    // Determine visual intensity based on streak
    let borderClass = "border-border";
    let glowClass = "";
    let streakColor = "text-text-muted";
    let fireEmoji = "🔥";

    if (streak >= 30) {
        borderClass = "border-accent-green";
        glowClass = "glow-green";
        streakColor = "text-accent-green";
        fireEmoji = "👑";
    } else if (streak >= 14) {
        borderClass = "border-accent-green";
        glowClass = "glow-green";
        streakColor = "text-accent-green";
        fireEmoji = "🔥";
    } else if (streak >= 7) {
        borderClass = "border-accent-amber";
        glowClass = "glow-amber";
        streakColor = "text-accent-amber";
    } else if (streak >= 3) {
        borderClass = "border-accent-amber";
        streakColor = "text-accent-amber";
    } else if (streak === 0) {
        fireEmoji = "💀";
        borderClass = "border-accent-red/30";
        streakColor = "text-accent-red";
    }

    return (
        <div className={`brutalist-card p-3 flex items-center justify-between ${borderClass} ${glowClass} transition-all duration-500`}>
            <div className="flex items-center gap-3">
                <span className="text-2xl">{fireEmoji}</span>
                <div>
                    <span className="text-[10px] uppercase tracking-[0.2em] text-text-muted block">
                        Disiplin Serisi
                    </span>
                    <span className={`text-lg font-bold ${streakColor}`}>
                        {streak} GÜN
                    </span>
                </div>
            </div>
            <div className="text-right">
                <span className="text-[9px] uppercase tracking-widest text-text-muted block">
                    En İyi
                </span>
                <span className="text-sm font-bold text-text-muted">
                    {bestStreak} gün
                </span>
            </div>
        </div>
    );
}

"use client";

import { weeklyTasks } from "@/data/mock";

interface WeeklyTrackerProps {
    completed: Record<string, boolean>;
    onToggle: (id: string) => void;
}

export default function WeeklyTracker({
    completed,
    onToggle,
}: WeeklyTrackerProps) {
    const total = weeklyTasks.length;
    const done = weeklyTasks.filter(task => completed[task.id]).length;
    const pct = Math.round((done / total) * 100);

    return (
        <section>
            {/* Section Header */}
            <div className="flex items-center justify-between mb-6 mt-8">
                <h2 className="text-xs font-bold uppercase tracking-[0.25em] text-text">
                    HAFTALIK TAKİP
                </h2>
                <span className="text-xs font-bold tabular-nums">
                    <span className={done === total ? "text-accent-green" : "text-text"}>
                        {done}
                    </span>
                    <span className="text-text-muted">/{total}</span>
                </span>
            </div>

            {/* Progress Bar */}
            <div className="w-full h-2 bg-surface brutalist-border mb-6 overflow-hidden">
                <div
                    className={`h-full progress-fill ${done === total ? "bg-accent-green glow-green" : "bg-accent-amber"
                        }`}
                    style={{ width: `${pct}%` }}
                />
            </div>

            {/* Task Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 items-stretch">
                {weeklyTasks.map((task, index) => {
                    const isOn = !!completed[task.id];

                    // Determine border & background based on whether it is checked
                    let cardClasses = "border-border hover:border-text-muted hover:bg-surface-hover";
                    let checkClasses = "bg-transparent text-text-muted";
                    let labelClasses = "text-text";

                    if (isOn) {
                        cardClasses = "border-accent-green/40 bg-accent-green/5 glow-green";
                        checkClasses = "bg-accent-green text-black border-accent-green";
                        labelClasses = "text-accent-green";
                    }

                    return (
                        <button
                            key={task.id}
                            onClick={() => onToggle(task.id)}
                            className={`
                                brutalist-card flex flex-1 items-center gap-3 text-left
                                transition-all duration-200 cursor-pointer p-4 h-full min-h-[44px]
                                ${cardClasses}
                            `}
                        >
                            {/* Status Indicator */}
                            <div
                                className={`
                                    mt-0.5 w-5 h-5 flex-shrink-0 brutalist-border flex items-center justify-center text-[11px] font-bold
                                    transition-colors duration-200
                                    ${checkClasses}
                                `}
                            >
                                {isOn ? "✓" : ""}
                            </div>

                            <div className="flex-1 min-w-0 flex items-center">
                                <span className="text-xl mr-3">{task.icon}</span>
                                <span
                                    className={`text-[12px] uppercase tracking-wide leading-snug font-bold ${labelClasses}`}
                                >
                                    {task.label}
                                </span>
                            </div>
                        </button>
                    );
                })}
            </div>
        </section>
    );
}
